  1	import React, { FC, useMemo } from 'react';
  2	
  3	import {
  4	  modelToGroupVersionKind,
  5	  NamespaceModel,
  6	  PodModel,
  7	} from '@kubevirt-ui/kubevirt-api/console';
  8	import { ResourceIcon } from '@openshift-console/dynamic-plugin-sdk';
  9	import {
 10	  Alert,
 11	  AlertVariant,
 12	  Label,
 13	  Text,
 14	  TreeView,
 15	  TreeViewDataItem,
 16	} from '@patternfly/react-core';
 17	import Loading from '@utils/components/Loading/Loading';
 18	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 19	import { isEmpty } from '@utils/utils';
 20	
 21	import { maxPreviewPods } from '../utils/const';
 22	import { matchedNs, podsFilterQuery, resourceListPathFromModel } from '../utils/utils';
 23	
 24	import useNetworkPolicyPodPreviewData from './hooks/useNetworkPolicyPodPreviewData';
 25	
 26	import './tree-view.css';
 27	
 28	type NetworkPolicyPodsPreviewProps = {
 29	  namespace?: string;
 30	  namespaceSelector?: string[][];
 31	  podSelector: string[][];
 32	};
 33	
 34	const NetworkPolicyPodsPreview: FC<NetworkPolicyPodsPreviewProps> = ({
 35	  namespace,
 36	  namespaceSelector,
 37	  podSelector,
 38	}) => {
 39	  const { t } = useNetworkingTranslation();
 40	  const { error, loaded, namespaces, pods, safeNsSelector, safePodSelector } =
 41	    useNetworkPolicyPodPreviewData({ namespaceSelector, podSelector });
 42	
 43	  // takes the first 'maxPreviewPods' received pods and groups them by namespace
 44	  const preview: {
 45	    pods?: TreeViewDataItem[];
 46	    total?: number;
 47	  } = useMemo(() => {
 48	    if (!loaded) {
 49	      return { pods: [], total: 0 };
 50	    }
 51	    // If there is a defined namespace selector, filter pods to remove
 52	    // those from non-matching namespaces
 53	    let filteredPods = pods;
 54	    if (namespaceSelector) {
 55	      filteredPods = filteredPods.filter(
 56	        (pod) => pod.metadata.namespace && matchedNs(namespaces).has(pod.metadata.namespace),
 57	      );
 58	    }
 59	    // Group pod TreeViewDataItem by namespace, up to a maximum of maxPreviewedPods entries
 60	    const podsByNs: { [key: string]: TreeViewDataItem[] } = {};
 61	    filteredPods.slice(0, maxPreviewPods).forEach((pod) => {
 62	      const ns = pod?.metadata?.namespace;
 63	      podsByNs[ns] ??= [];
 64	      podsByNs[ns].push({
 65	        icon: <ResourceIcon groupVersionKind={modelToGroupVersionKind(PodModel)} />,
 66	        name: pod?.metadata?.name,
 67	      });
 68	    });
 69	    // Then convert the above groups of pod TreeViewDataItems to subchildren of
 70	    // the namespaces' TreeViewDataItems
 71	    const podTreeEntries = Object.entries(podsByNs).map(
 72	      ([ns, podsTree]): TreeViewDataItem => ({
 73	        children: podsTree,
 74	        defaultExpanded: true,
 75	        icon: <ResourceIcon kind={NamespaceModel.kind} />,
 76	        name: ns,
 77	      }),
 78	    );
 79	    return {
 80	      pods: podTreeEntries,
 81	      total: filteredPods.length,
 82	    };
 83	  }, [loaded, namespaceSelector, namespaces, pods]);
 84	
 85	  const labelsArray: string[][] = Object.entries(safePodSelector.matchLabels || {});
 86	  const labelList = labelsArray.map(([label, value]) => `${label}=${value}`);
 87	  const labelBadges = labelsArray.map(([label, value]) => (
 88	    <Label color="green" key={label} value={value}>
 89	      {label}={value}
 90	    </Label>
 91	  ));
 92	
 93	  if (error) {
 94	    return (
 95	      <Alert
 96	        data-test="pods-preview-alert"
 97	        isInline
 98	        title={t("Can't preview pods")}
 99	        variant={AlertVariant.danger}
100	      >
101	        <Text component="p">{error.toString()}</Text>
102	      </Alert>
103	    );
104	  }
105	
106	  if (loaded && isEmpty(preview?.pods)) {
107	    return (
108	      <div data-test="pods-preview-title">
109	        {t('No pods matching the provided labels in the current namespace')}
110	      </div>
111	    );
112	  }
113	
114	  if (!loaded) {
115	    return <Loading />;
116	  }
117	
118	  return (
119	    <>
120	      <div data-test="pods-preview-title">
121	        {!isEmpty(labelList) ? (
122	          <>
123	            {t('List of pods matching')} {labelBadges}
124	          </>
125	        ) : (
126	          t('List of pods')
127	        )}
128	      </div>
129	      <TreeView
130	        className="network-policy-pods-preview"
131	        data={preview?.pods}
132	        data-test="pods-preview-tree"
133	        hasGuides
134	      />
135	      {preview?.total > maxPreviewPods && isEmpty(Object.keys(safeNsSelector.matchLabels)) ? (
136	        <a
137	          data-test="pods-preview-footer-link"
138	          href={`${resourceListPathFromModel(PodModel, namespace)}${podsFilterQuery(preview?.total, labelList)}`}
139	          rel="noopener noreferrer"
140	          target="_blank"
141	        >
142	          {t('Showing {{shown}} from {{total}} results', {
143	            shown: maxPreviewPods,
144	            total: preview.total,
145	          })}
146	        </a>
147	      ) : (
148	        <p data-test="pods-preview-footer">
149	          {t('View all {{total}} results', {
150	            total: preview.total,
151	          })}
152	        </p>
153	      )}
154	    </>
155	  );
156	};
157	
158	export default NetworkPolicyPodsPreview;

